// It's a square, each side (width & height) is PIXELS_PER_SIDE long.
// And flip >>some<< lines, >>not<< flip everything!
const PIXELS_PER_SIDE: usize = 8;
const PIXELS_PER_LINE: usize = PIXELS_PER_SIDE;
const BYTES_PER_PIXEL: usize = 4;

/// Flip a single line of 4-byte pixels in-place.
///
/// Fast path: reinterpret as `&mut [u32]` and swap pixels as words (1 swap per pixel).
/// Fallback: if the slice isn't 4-byte aligned, swap 4 bytes at a time using ptr swap.
fn flip_line(line_bytes: &mut [u8]) {
    assert_eq!(
        line_bytes.len(),
        PIXELS_PER_LINE * BYTES_PER_PIXEL,
        "unexpected line length"
    );
    assert_eq!(line_bytes.len() % BYTES_PER_PIXEL, 0);

    // Fast path if the buffer is properly aligned for u32.
    let (head, words, tail) = unsafe { line_bytes.align_to_mut::<u32>() };
    if head.is_empty() && tail.is_empty() {
        // Swap pixels (u32) from ends towards center.
        if words.len() <= 1 {
            return;
        }
        let mut i = 0usize;
        let mut j = words.len() - 1;
        while i < j {
            words.swap(i, j);
            i += 1;
            j -= 1;
        }
        return;
    }

    // Fallback: unaligned slice; swap 4 bytes at a time.
    let mut left = 0usize;
    let mut right = line_bytes.len() - BYTES_PER_PIXEL;

    while left < right {
        unsafe {
            ptr::swap_nonoverlapping(
                line_bytes.as_mut_ptr().add(left),
                line_bytes.as_mut_ptr().add(right),
                BYTES_PER_PIXEL,
            );
        }
        left += BYTES_PER_PIXEL;
        right -= BYTES_PER_PIXEL;
    }
}

fn main() {
    const ORIGINAL_BYTES: [u8; BYTES_PER_PIXEL * PIXELS_PER_LINE] = [
        // 0
