",
  "main.rs": "use std::fmt;

#[derive(Debug, Clone, PartialEq, Eq)]
enum TokenizeError {
    UnclosedSingleQuote,
}

impl fmt::Display for TokenizeError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            TokenizeError::UnclosedSingleQuote => write!(f, "unclosed single quote"),
        }
    }
}

/// Tokenize a command line roughly like a POSIX shell with:
/// - whitespace splitting
/// - single quotes (no escapes inside)
///
/// This is enough to handle cases like:
/// ` one  ' two  'three    four` -> ["one", " two  three", "four"]
fn tokenize(input: &str) -> Result<Vec<String>, TokenizeError> {
    #[derive(Copy, Clone, Debug, PartialEq, Eq)]
    enum State {
        Normal,
        InSingleQuote,
    }

    let mut out: Vec<String> = Vec::new();
    let mut cur = String::new();

    // Tracks whether we have started an argument, even if it's currently empty.
    // Needed so that "''" yields one empty token.
    let mut has_token = false;

    let mut state = State::Normal;

    for ch in input.chars() {
        match state {
            State::Normal => match ch {
                '\'' => {
                    state = State::InSingleQuote;
                    has_token = true;
                }
                c if c.is_whitespace() => {
                    if has_token {
                        out.push(std::mem::take(&mut cur));
                        has_token = false;
                    }
                }
                c => {
                    cur.push(c);
                    has_token = true;
                }
            },
            State::InSingleQuote => {
                if ch == '\'' {
                    state = State::Normal;
                } else {
                    cur.push(ch);
                    has_token = true;
                }
            }
        }
    }

    if state == State::InSingleQuote {
        return Err(TokenizeError::UnclosedSingleQuote);
    }

    if has_token {
        out.push(cur);
    }

    Ok(out)
}

fn main() {
    let input = " one  ' two  'three    four";
    let tokens = tokenize(input).unwrap();

    println!("input: {input:?}");
    println!("{} args:", tokens.len());
    for t in tokens {
        println!("<{t}>");
    }
}
"
}
