                        continue;
                    }
                    if bi.criterion(&elems[j]) < cutoff {
                        nb.push(j);
                    }
                }
                nb
            })
            .collect();

        // Write back (single-threaded, but cheap compared to O(n^2) compute).
        for (b, nb) in self.elems.iter_mut().zip(all_nbs) {
            b.nb = nb;
        }
    }
}

fn main() {
