            B::new(1.0, 2.0, 0.0),
            B::new(10.0, 10.0, 10.0),
        ],
        cutoff: 1.5, // compare squared distance
    };

    let mut a_seq = a.clone();
    a_seq.build_lists_pairwise();

    let mut a_par = a.clone();
    a_par.build_lists_parallel();

    println!("Sequential pairwise (updates both sides in one pass):");
    for (i, b) in a_seq.elems.iter().enumerate() {
        println!("  i={i} nb={:?}", b.nb);
    }

    println!("\nParallel (two-phase):");
    for (i, b) in a_par.elems.iter().enumerate() {
        println!("  i={i} nb={:?}", b.nb);
    }

    // Sanity check: because criterion is symmetric, both approaches produce the same neighbor sets.
    // (Order may differ, so compare sorted.)
    for i in 0..a_seq.get_nelems() {
        let mut s1 = a_seq.elems[i].nb.clone();
        let mut s2 = a_par.elems[i].nb.clone();
        s1.sort_unstable();
        s2.sort_unstable();
        assert_eq!(s1, s2, "Mismatch at i={i}");
    }

    println!("\nOK: sequential and parallel neighbor lists match.");
}
