fn resolve_value(value: Value, base_dir: &Path) -> Result<Value, Box<dyn Error>> {
    match value {
        Value::Object(map) => {
            // Treat {"$ref": "..."} as a reference object.
            if map.len() == 1 {
                if let Some(Value::String(r)) = map.get("$ref") {
                    return resolve_ref(r, base_dir);
                }
            }

            // Otherwise, recursively resolve inside object values.
            let mut out: BTreeMap<String, Value> = BTreeMap::new();
            for (k, v) in map {
                out.insert(k, resolve_value(v, base_dir)?);
            }
            Ok(Value::Object(out.into_iter().collect()))
        }
        Value::Array(arr) => {
            let mut out = Vec::with_capacity(arr.len());
            for v in arr {
                out.push(resolve_value(v, base_dir)?);
            }
            Ok(Value::Array(out))
        }
        other => Ok(other),
    }
}

fn resolve_ref(r: &str, base_dir: &Path) -> Result<Value, Box<dyn Error>> {
    // Very small JSON Reference resolver:
    //   "./a.json#/p_list"  -> file "./a.json" relative to base_dir, then JSON Pointer "/p_list"

    let (path_part, frag_part) = match r.split_once('#') {
        Some((p, f)) => (p, f),
        None => (r, ""),
    };

    let ref_path = if path_part.is_empty() {
        return Err("$ref without a path is not supported in this demo".into());
    } else {
        base_dir.join(path_part)
    };

    let text = fs::read_to_string(&ref_path)?;
    let doc: Value = serde_json::from_str(&text)?;

    let mut selected = if frag_part.is_empty() {
        doc
    } else {
        // frag_part comes from after '#'. In JSON Pointer form it should start with '/'.
        // Example: "#/p_list" => frag_part == "/p_list".
        let ptr = frag_part;
        doc.pointer(ptr)
            .ok_or_else(|| format!("JSON pointer not found: {} in {}", ptr, ref_path.display()))?
            .clone()
    };

    // Resolve nested $ref inside the referenced content, relative to the referenced file.
    let next_base = ref_path.parent().unwrap_or(base_dir);
    selected = resolve_value(selected, next_base)?;

    Ok(selected)
}

fn main() -> Result<(), Box<dyn Error>> {
    // Self-contained demo: create a temp directory with a.json and b.json.
    let dir = std::env::temp_dir().join("serde_demo_refs");
    fs::create_dir_all(&dir)?;

    let a_path = dir.join("a.json");
    let b_path = dir.join("b.json");

    fs::write(
        &a_path,
        r#"{
