    let json_data = fs::read_to_string(&b_path)?;
    let raw: Value = serde_json::from_str(&json_data)?;

    let resolved = resolve_value(raw, b_path.parent().unwrap())?;
    let a_obj: A = serde_json::from_value(resolved)?;

    for p in &a_obj.path_list {
        println!("{}", p.display());
    }

    Ok(())
}
