        let value = value.ok_or_else(|| de::Error::missing_field("value"))?;

        match kind.as_str() {
            "int" => value
                .as_i64()
                .map(B::Int)
                .ok_or_else(|| de::Error::custom("expected integer for value")),
            "text" => value
                .as_str()
                .map(|s| B::Text(s.to_owned()))
                .ok_or_else(|| de::Error::custom("expected string for value")),
            other => Err(de::Error::unknown_variant(other, &["int", "text"])),
