        // indexing borrows `self` for the duration of the call to `next()`.
        // The standard library solves this for slice::IterMut using raw pointers.
        // We do the same.
        let dims = self.dims.clone();
        let len = self.store.len();
        let ptr = self.store.as_mut_ptr();

        ArrayIterMut {
            ptr,
            len,
            dims: dims.clone(),
            idx_iter: IndexIter::new(dims),
            _marker: PhantomData, // ties returned &mut T to the original `&mut Array<T>` borrow
        }
    }
