        &self.store[i]
    }
}

impl<T> IndexMut<&[usize]> for Array<T> {
    fn index_mut(&mut self, index: &[usize]) -> &mut Self::Output {
        let i = self.linear_index(index);
        &mut self.store[i]
    }
}

/// Row-major linear index.
fn linear_index(dims: &[usize], idx: &[usize]) -> usize {
    assert_eq!(dims.len(), idx.len());
    let mut stride = 1usize;
    let mut lin = 0usize;

    // last axis varies fastest
    for ((&d, &i), axis) in dims.iter().zip(idx.iter()).zip(0..) {
        assert!(i < d, "index out of bounds at axis {axis}: {i} >= {d}");
    }

    for k in (0..dims.len()).rev() {
        lin += idx[k] * stride;
        stride *= dims[k];
    }
    lin
}

fn bump_index(dims: &[usize], idx: &mut [usize]) {
    for axis in (0..dims.len()).rev() {
        idx[axis] += 1;
        if idx[axis] < dims[axis] {
            return;
        }
        idx[axis] = 0;
    }
}

/// Iterator over all cartesian indices for `dims`.
#[derive(Debug, Clone)]
struct IndexIter {
    dims: Vec<usize>,
    cur: Vec<usize>,
    done: bool,
}

impl IndexIter {
    fn new(dims: Vec<usize>) -> Self {
        assert!(!dims.is_empty());
        Self {
            cur: vec![0; dims.len()],
            dims,
            done: false,
        }
    }
}

impl Iterator for IndexIter {
    type Item = Vec<usize>;

    fn next(&mut self) -> Option<Self::Item> {
        if self.done {
            return None;
        }

        let out = self.cur.clone();

        // advance
        for axis in (0..self.dims.len()).rev() {
            self.cur[axis] += 1;
            if self.cur[axis] < self.dims[axis] {
                return Some(out);
            }
            self.cur[axis] = 0;
            if axis == 0 {
                self.done = true;
                return Some(out);
            }
        }

        unreachable!();
    }
}

#[derive(Debug)]
pub struct ArrayIter<'a, T> {
    array: &'a Array<T>,
    idx_iter: IndexIter,
}

impl<'a, T> Iterator for ArrayIter<'a, T> {
    type Item = (Vec<usize>, &'a T);

    fn next(&mut self) -> Option<Self::Item> {
        let idx = self.idx_iter.next()?;
        let v = &self.array[&idx[..]];
        Some((idx, v))
    }
}

#[derive(Debug)]
pub struct ArrayIterMut<'a, T> {
    ptr: *mut T,
    len: usize,
    dims: Vec<usize>,
    idx_iter: IndexIter,
    _marker: PhantomData<&'a mut [T]>,
}

impl<'a, T> Iterator for ArrayIterMut<'a, T> {
    type Item = (Vec<usize>, &'a mut T);

    fn next(&mut self) -> Option<Self::Item> {
        let idx = self.idx_iter.next()?;
        let lin = linear_index(&self.dims, &idx);
        assert!(lin < self.len);

        // SAFETY:
        // - `ptr` came from `Array::iter_mut(&mut self)` which borrowed the whole
        //   array mutably for lifetime `'a`.
        // - `IndexIter` visits each element exactly once, so we never return two
        //   mutable references to the same element.
        // - Caller cannot call `next()` again while holding a mutable borrow of
        //   this iterator itself, but they *can* keep prior `&'a mut T`s; the
        //   uniqueness guarantee relies on us never yielding the same `lin` twice.
        let v = unsafe { &mut *self.ptr.add(lin) };
        Some((idx, v))
    }
}

fn main() {
    let mut a = Array::from_fn(vec![2, 3], |idx| {
        // value = 10 * row + col
        (idx[0] as i32) * 10 + (idx[1] as i32)
    });

