// In embedded code you'd typically put the counter behind a critical-section Mutex
// (not an AtomicUsize) on targets that don't have real atomic instructions.
static CHANNEL_INDEX: Mutex<Cell<usize>> = Mutex::new(Cell::new(0));

/// A `fetch_add` implemented using a critical section.
///
/// Note: there is no `Ordering` parameter here because critical sections/mutexes
/// provide synchronization via mutual exclusion rather than atomic memory orderings.
///
/// * If your original `fetch_add(..., Ordering::Relaxed)` only needed atomicity
///   (a unique incrementing index), this is the direct replacement.
/// * If you needed acquire/release-style ordering with other data, you would
///   instead put that data behind the same critical section (or use a proper
///   cross-core lock), not “fix it” with a different atomic Ordering.
fn fetch_add_cs(inc: usize) -> usize {
    critical_section::with(|cs| {
        let cell = CHANNEL_INDEX.borrow(cs);
        let old = cell.get();
        cell.set(old.wrapping_add(inc));
        old
    })
}

fn main() {
    // Demonstrate correctness under concurrency on the host.
    // On RP2040 the critical_section implementation must be cross-core (spinlock-based),
    // otherwise two cores could race.

    let threads = 4;
    let iters_per_thread = 50_000;

    let handles: Vec<_> = (0..threads)
        .map(|_| {
            thread::spawn(move || {
                for _ in 0..iters_per_thread {
                    let _ = fetch_add_cs(1);
                }
            })
        })
        .collect();

    for h in handles {
        h.join().unwrap();
    }

    let final_value = critical_section::with(|cs| CHANNEL_INDEX.borrow(cs).get());
    println!(
        "final counter = {final_value} (expected {})",
        threads * iters_per_thread
    );

    // Summary (why no Ordering?):
    // - Atomic orderings control compiler/CPU reordering of memory operations *between threads*
    //   while still being lock-free.
    // - A critical section is a lock: it provides mutual exclusion and acts like an
    //   acquire/release synchronization boundary around the whole block.
    // - Therefore the correct replacement for `fetch_add(..., Relaxed)` is simply the
    //   read-modify-write inside the critical section; no Ordering is needed.
}
