#[derive(Clone, Copy, Debug, Default)]
struct Pt {
    x: f64,
    y: f64,
}

impl Pt {
    fn new(x: f64, y: f64) -> Self {
        Self { x, y }
    }
}

impl From<ElementPoint> for Pt {
    fn from(p: ElementPoint) -> Self {
        Self {
            x: p.x,
            y: p.y,
        }
    }
}

#[derive(Clone, Copy)]
struct DragCtx {
    // continuously updated by the parent surface
    mouse: Signal<Pt>,

    // set by points and/or the surface
    dragging: Signal<bool>,
    active_id: Signal<Option<usize>>,

    // captured on drag start
    origin_mouse: Signal<Pt>,
    origin_point: Signal<Pt>,
}

fn app() -> Element {
    // Provide a "custom event" mechanism via signals in context.
    // Parent updates `mouse`; children react to it without needing to attach DOM listeners.
    let mouse = use_signal(Pt::default);
    let dragging = use_signal(|| false);
    let active_id = use_signal(|| None);
    let origin_mouse = use_signal(Pt::default);
    let origin_point = use_signal(Pt::default);

    use_context_provider(|| DragCtx {
        mouse,
        dragging,
        active_id,
        origin_mouse,
        origin_point,
    });

    // Some draggable points
    let p0 = use_signal(|| Pt::new(120.0, 120.0));
    let p1 = use_signal(|| Pt::new(260.0, 160.0));
    let p2 = use_signal(|| Pt::new(420.0, 240.0));

    rsx! {
        style {
            r#"
            body { font-family: system-ui, sans-serif; }
            .wrap { padding: 16px; }
            .panel { display: flex; gap: 16px; align-items: flex-start; }
            .card { border: 1px solid #ddd; border-radius: 10px; padding: 12px; }
            svg { border: 1px solid #ccc; border-radius: 10px; background: #fafafa; }
            .pt { fill: #2f6feb; stroke: #0b2f6b; stroke-width: 2; cursor: grab; }
            .pt:active { cursor: grabbing; }
            "#
        }

        div { class: "wrap",
            h2 { "Dragging SVG circles (parent listens, children react via context)" }

            div { class: "panel",
                div { class: "card",
                    DragSurface {
                        width: 600,
                        height: 360,
                        Point { id: 0, position: p0 }
                        Point { id: 1, position: p1 }
                        Point { id: 2, position: p2 }
                    }
                }

                DebugPanel {}
            }
        }
    }
}

#[component]
fn DragSurface(width: i32, height: i32, children: Element) -> Element {
    let drag = use_context::<DragCtx>();

    rsx! {
        svg {
            width: "{width}",
            height: "{height}",
            view_box: "0 0 {width} {height}",

            // Parent listens to mouse events on the whole surface.
            // This fixes the "breaks when leaving the dragged element" problem.
            onmousemove: move |e| {
                drag.mouse.set(Pt::from(e.element_coordinates()));
            },
            onmouseup: move |_| {
                drag.dragging.set(false);
                drag.active_id.set(None);
            },
            onmouseleave: move |_| {
                drag.dragging.set(false);
                drag.active_id.set(None);
            },

            // background
            rect { x: 0, y: 0, width: "{width}", height: "{height}", fill: "transparent" }

            {children}
        }
    }
}

#[component]
fn Point(id: usize, #[props(!partial_eq)] position: Signal<Pt>) -> Element {
    let drag = use_context::<DragCtx>();

    // This effect is the "custom event handler": it runs whenever the signals
    // it reads change (mouse move, drag start/stop, etc).
    use_effect(move || {
        let active = *drag.active_id.read() == Some(id);
        let dragging = *drag.dragging.read();

        if active && dragging {
            let mouse = *drag.mouse.read();
            let origin_mouse = *drag.origin_mouse.read();
            let origin_point = *drag.origin_point.read();

            let next = Pt::new(
                origin_point.x + (mouse.x - origin_mouse.x),
                origin_point.y + (mouse.y - origin_mouse.y),
            );
            position.set(next);
        }
    });

    let p = *position.read();

    rsx! {
        circle {
            class: "pt",
            cx: "{p.x}",
            cy: "{p.y}",
            r: "10",

            // Start drag on the point.
            onmousedown: move |e| {
                e.stop_propagation();

                drag.active_id.set(Some(id));
                drag.dragging.set(true);

                drag.origin_mouse.set(Pt::from(e.element_coordinates()));
                drag.origin_point.set(*position.read());
            },
        }
    }
}

#[component]
fn DebugPanel() -> Element {
    let drag = use_context::<DragCtx>();
    let mouse = *drag.mouse.read();
    let dragging = *drag.dragging.read();
    let active = *drag.active_id.read();

    rsx! {
        div { class: "card",
            h3 { "Debug" }
            div { "mouse: ({mouse.x:.1}, {mouse.y:.1})" }
            div { "dragging: {dragging}" }
            div { "active id: {active:?}" }
            p {
                "The parent <svg> owns the real DOM listeners. Each point reacts to changes via signals in context (a "
                "custom event" pattern), instead of attaching its own mousemove handler." 
            }
        }
    }
}
"
