impl ShmBuf {
    fn create(pixel_bytes: usize) -> io::Result<Self> {
        let pid = std::process::id();
        let ns = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap_or_default()
            .as_nanos();
        // POSIX shm_open names must start with '/'
        let name = CString::new(format!("/kitty-rust-anim-{}-{}", pid, ns)).unwrap();

        unsafe {
            let fd = libc::shm_open(
                name.as_ptr(),
                libc::O_CREAT | libc::O_EXCL | libc::O_RDWR,
                0o600,
            );
            if fd < 0 {
                return Err(io::Error::last_os_error());
            }

            if libc::ftruncate(fd, pixel_bytes as off_t) != 0 {
                let e = io::Error::last_os_error();
                libc::close(fd);
                libc::shm_unlink(name.as_ptr());
                return Err(e);
            }

            let ptr = libc::mmap(
                ptr::null_mut(),
                pixel_bytes as size_t,
                libc::PROT_READ | libc::PROT_WRITE,
                libc::MAP_SHARED,
                fd,
                0,
            );
            if ptr == libc::MAP_FAILED {
                let e = io::Error::last_os_error();
                libc::close(fd);
                libc::shm_unlink(name.as_ptr());
                return Err(e);
            }

            Ok(Self {
                name,
                fd,
                ptr: ptr as *mut u8,
                len: pixel_bytes,
            })
        }
    }

    fn as_mut_slice(&mut self) -> &mut [u8] {
        unsafe { slice::from_raw_parts_mut(self.ptr, self.len) }
    }

    fn name_str(&self) -> &CStr {
        self.name.as_c_str()
    }
}

impl Drop for ShmBuf {
    fn drop(&mut self) {
        unsafe {
            libc::munmap(self.ptr as *mut c_void, self.len as size_t);
            libc::close(self.fd);
            libc::shm_unlink(self.name.as_ptr());
        }
    }
