  "main.rs": "use futures::future::{BoxFuture, FutureExt};
use std::{
    collections::HashMap,
    future::{ready, Future, Ready},
    sync::Arc,
};

// ===== Minimal request/response types =====
#[derive(Debug)]
pub struct Request;

#[derive(Debug)]
pub struct Response(pub String);

// ===== Unified stored handler type: (&Request) -> BoxFuture<Response> =====
type HandlerFn = dyn for<'a> Fn(&'a Request) -> BoxFuture<'a, Response> + Send + Sync + 'static;

#[derive(Clone)]
pub struct Handler(Arc<HandlerFn>);

impl Handler {
    pub fn call<'a>(&'a self, req: &'a Request) -> BoxFuture<'a, Response> {
        (self.0)(req)
    }
}

// ===== Trait that both sync and async handlers can implement =====
//
// Key point: the return future type may depend on the input lifetime 'a.
// We express that with a GAT.
pub trait RouteHandler: Send + Sync + 'static {
    type Fut<'a>: Future<Output = Response> + Send + 'a
    where
        Self: 'a;

    fn call<'a>(&'a self, req: &'a Request) -> Self::Fut<'a>;
}

// Async handler impl: F(&Request) -> (some future that may borrow req)
impl<F> RouteHandler for F
where
    F: Send + Sync + 'static,
    for<'a> F: Fn(&'a Request),
    for<'a> <F as FnOnce<(&'a Request,)>>::Output: Future<Output = Response> + Send + 'a,
{
    type Fut<'a> = <F as FnOnce<(&'a Request,)>>::Output
    where
        Self: 'a;

    fn call<'a>(&'a self, req: &'a Request) -> Self::Fut<'a> {
        (self)(req)
    }
}

// Sync handler impl: F(&Request) -> Response
impl<F> RouteHandler for F
where
    F: Send + Sync + 'static,
    for<'a> F: Fn(&'a Request) -> Response,
{
    type Fut<'a> = Ready<Response>
    where
        Self: 'a;

    fn call<'a>(&'a self, req: &'a Request) -> Self::Fut<'a> {
        ready((self)(req))
    }
}

// Convert any RouteHandler into the boxed-future Handler we store.
impl<F> From<F> for Handler
where
    F: RouteHandler,
{
    fn from(f: F) -> Self {
        let f = Arc::new(f);
        Handler(Arc::new(move |req| {
            let f = Arc::clone(&f);
            async move { f.call(req).await }.boxed()
        }))
    }
}

// ===== Server that stores handlers =====
pub struct Server {
    routes: HashMap<String, Handler>,
}

impl Server {
    pub fn new() -> Self {
        Self {
            routes: HashMap::new(),
        }
    }

    // One ergonomic method: accepts BOTH sync and async handlers.
    pub fn add_route<H>(&mut self, path: &str, handler: H)
    where
        H: Into<Handler>,
    {
        self.routes.insert(path.to_string(), handler.into());
    }

    pub fn handle<'a>(&'a self, path: &str, req: &'a Request) -> BoxFuture<'a, Response> {
        self.routes[path].call(req)
    }
}

// ===== Example user code =====
fn sync_handler(_req: &Request) -> Response {
    Response("from sync handler".to_string())
}

async fn async_handler(_req: &Request) -> Response {
    Response("from async handler".to_string())
}

fn main() {
    let mut server = Server::new();

    // Same API for both:
    server.add_route("/sync", sync_handler);
    server.add_route("/async", async_handler);

    let req = Request;

    let sync_resp = futures::executor::block_on(server.handle("/sync", &req));
    let async_resp = futures::executor::block_on(server.handle("/async", &req));

    println!("/sync  -> {sync_resp:?}");
    println!("/async -> {async_resp:?}");
}
"
}
