  "main.rs": "use anyhow::{bail, Context, Result};
use chrono::{DateTime, NaiveDateTime, Utc};

/// Parses the kinds of ISO-ish strings LanceDB may return for timestamp fields,
/// e.g.:
/// - "1970-01-01T00:00:00"
/// - "2025-08-02T17:35:41.409"
/// - sometimes with a trailing '.' (e.g. "...41.")
/// - optionally RFC3339 with timezone (e.g. "...41.409Z" or "...41+00:00")
///
/// Returns a chrono::DateTime<Utc>.
fn parse_lancedb_datetime(s: &str) -> Result<DateTime<Utc>> {
    let s = s.trim().trim_matches('"');
    let s = s.strip_suffix('.').unwrap_or(s); // handle a possible trailing '.'

    // 1) If it's already RFC3339 (has Z / offset), parse directly.
    if let Ok(dt) = DateTime::parse_from_rfc3339(s) {
        return Ok(dt.with_timezone(&Utc));
    }

    // 2) If it looks like "YYYY-MM-DDTHH:MM:SS(.fff)" without timezone,
    // assume UTC and parse as NaiveDateTime.
    // Try with optional fractional seconds first, then without.
    for fmt in [
        "%Y-%m-%dT%H:%M:%S%.f", // supports ".409" etc.
        "%Y-%m-%dT%H:%M:%S",    // no fractional seconds
    ] {
        if let Ok(ndt) = NaiveDateTime::parse_from_str(s, fmt) {
            return Ok(DateTime::<Utc>::from_naive_utc_and_offset(ndt, Utc));
        }
    }

    // 3) Last resort: try adding 'Z' and parse as RFC3339.
    // (Some parsers require a timezone; this covers "..." -> "...Z".)
    let with_z = format!("{s}Z");
    if let Ok(dt) = DateTime::parse_from_rfc3339(&with_z) {
        return Ok(dt.with_timezone(&Utc));
    }

    bail!("Unrecognized datetime format: {s}")
}

/// Convert the parsed datetime to a unix integer.
/// Use milliseconds since epoch since LanceDB often shows millisecond precision.
fn date_string_to_unix_millis(s: &str) -> Result<i64> {
    let dt = parse_lancedb_datetime(s).with_context(|| format!("parsing '{s}'"))?;
    Ok(dt.timestamp_millis())
}

fn main() -> Result<()> {
    let samples = [
        "1970-01-01T00:00:00",
        "2025-08-02T17:35:41.409",
        "2025-08-04T01:48:44.017",
        "2025-08-04T23:02:20.584",
        "2025-08-05T00:08:57.350",
        "2025-08-10T18:31:26.628",
        // some extras you might see:
        "2025-08-10T18:31:26.628Z",
        "2025-08-10T18:31:26Z",
        "2025-08-10T18:31:26.628+00:00",
        "2025-08-10T18:31:26.",
        "\"2025-08-10T18:31:26.628\"",
    ];

    for s in samples {
        match parse_lancedb_datetime(s) {
            Ok(dt) => {
                let ms = dt.timestamp_millis();
                let secs = dt.timestamp();
                println!("{s:35} -> {dt:?} -> unix_secs={secs}, unix_millis={ms}");
            }
            Err(e) => {
                println!("{s:35} -> ERROR: {e:#}");
            }
        }
    }

    // Demonstrate the exact function requested (integer conversion)
    let s = "2025-08-02T17:35:41.409";
    let ms = date_string_to_unix_millis(s)?;
    println!("\nAs integer (millis): {s} -> {ms}");

    Ok(())
}
"
}
```

