    if server.name.is_empty() {
        return Err(de::Error::custom("server.name must not be empty"));
    }
    Ok(server.name)
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let json = r#"
    {
      "name": "Name",
      "server": {
        "name": "Server"
      }
    }
    "#;

    let c: Character = serde_json::from_str(json)?;
    println!("{c:?}");
    Ok(())
}
"
}
