fn column_means(m: &DMatrix<f64>) -> RowDVector<f64> {
    let n = m.nrows();
    let k = m.ncols();

    let mut means = RowDVector::<f64>::zeros(k);
    for j in 0..k {
        let mut sum = 0.0;
        for i in 0..n {
            sum += m[(i, j)];
        }
        means[j] = sum / (n as f64);
    }
    means
}

fn main() {
    // n x k data matrix: rows = observations, cols = features
    let m = DMatrix::<f64>::from_row_slice(
        4,
        3,
        &[
            1.0, 2.0, 3.0, // row 0
            4.0, 5.0, 6.0, // row 1
            7.0, 8.0, 9.0, // row 2
            2.0, 4.0, 6.0, // row 3
        ],
    );

    let mean = column_means(&m); // 1 x k row vector

    // "Broadcast" the 1 x k mean to an n x k matrix by repeating the row n times.
    // This is the idiomatic nalgebra way to do it.
    let centered = &m - mean.clone().repeat(m.nrows(), 1);

    println!("Original m:\n{m}\n");
    println!("Column means (row vector):\n{mean}\n");
    println!("Centered (each column has mean ~0):\n{centered}\n");

    // Example: covariance = (X^T X) / (n - 1)
    let n = m.nrows();
    let cov = (&centered.transpose() * &centered) / ((n - 1) as f64);
    println!("Covariance matrix:\n{cov}\n");
}
