use std::{
    future::Future,
    pin::Pin,
    task::{Context, Poll},
    time::Duration,
};

enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Polls a future exactly once, synchronously.
///
/// Note: This uses a noop waker because we only want to know whether the future
/// is ready *right now*. If it isn't, you should hand it off to a real executor
/// (e.g. by spawning and awaiting it).
fn try_poll<X>(mut future: Pin<&mut impl Future<Output = X>>) -> TryPollResult<X> {
    let mut cx = Context::from_waker(noop_waker_ref());
    match future.as_mut().poll(&mut cx) {
        Poll::Ready(x) => TryPollResult::Ready(x),
        Poll::Pending => TryPollResult::Pending,
    }
}

/// Non-async function called from async context.
/// If `fut` is immediately ready, use it inline.
/// Otherwise, spawn a task that awaits it.
fn inline_or_spawn<F>(fut: F) -> Option<tokio::task::JoinHandle<F::Output>>
where
    F: Future + Send + 'static,
    F::Output: Send + 'static,
{
    // Box::pin lets us poll it (even if it's !Unpin) and still move it into the spawned task.
    let mut fut = Box::pin(fut);

    match try_poll(fut.as_mut()) {
        TryPollResult::Ready(val) => {
            println!("inline: future was immediately ready");
            println!("inline: value = {:?}", &val as *const _ as usize); // just show we got it
            drop(val);
            None
        }
        TryPollResult::Pending => {
            println!("spawn: future was pending; spawning a task to await it");
            Some(tokio::spawn(async move {
                let val = fut.await;
                val
            }))
        }
    }
}

#[tokio::main(flavor = "multi_thread")]
async fn main() {
    // Immediately-ready future (no .await inside).
    let h1 = inline_or_spawn(async { 123_i32 });
    assert!(h1.is_none());

    // Pending future (contains an .await).
    let h2 = inline_or_spawn(async {
        tokio::time::sleep(Duration::from_millis(200)).await;
        456_i32
    })
    .expect("should have spawned");

    let v2 = h2.await.expect("task panicked");
    println!("spawned task: value = {v2}");
}
