name = "enum_dispatch_layers_demo"
version = "0.1.0"
edition = "2021"

[dependencies]
enum_dispatch = "0.3"
",
  "main.rs": "use enum_dispatch::enum_dispatch;

// In a real multi-crate setup, you can put this macro in your `al` crate and
// `#[macro_export]` it, so both `al` and `bl` can share the method list.
macro_rules! rest_api {
    // The canonical trait in `al` (signatures only)
    (core) => {
        fn get(&self, id: u32) -> String;
        fn post(&self, body: &str) -> usize;
        fn delete(&self, id: u32) -> bool;
    };

    // The dispatch trait in `bl` (default bodies that forward to `al`)
    (wrapper) => {
        fn get(&self, id: u32) -> String {
            <Self as crate::al::RestCore>::get(self, id)
        }
        fn post(&self, body: &str) -> usize {
            <Self as crate::al::RestCore>::post(self, body)
        }
        fn delete(&self, id: u32) -> bool {
            <Self as crate::al::RestCore>::delete(self, id)
        }
    };
}

mod al {
    // Abstract layer: defines the canonical trait.
    pub trait RestCore {
        crate::rest_api!(core);
    }
}

mod il {
    // Implementation layer: types implementing the canonical trait.
    use crate::al::RestCore;

    #[derive(Debug, Clone)]
    pub struct Foo;

    #[derive(Debug, Clone)]
    pub struct Boo;

    impl RestCore for Foo {
        fn get(&self, id: u32) -> String {
            format!("Foo::get({id})")
        }
        fn post(&self, body: &str) -> usize {
            body.len() + 10
        }
        fn delete(&self, id: u32) -> bool {
            id % 2 == 0
        }
    }

    impl RestCore for Boo {
        fn get(&self, id: u32) -> String {
            format!("Boo::get({id})")
        }
        fn post(&self, body: &str) -> usize {
            body.len() + 20
        }
        fn delete(&self, id: u32) -> bool {
            id % 2 == 1
        }
    }
}

mod bl {
    // Business layer: define a *local* dispatch trait + enum_dispatch enum.
    // The local trait forwards (via default methods) into `al::RestCore`.
    use super::{al, il};
    use enum_dispatch::enum_dispatch;

    #[enum_dispatch]
    pub trait Rest {
        crate::rest_api!(wrapper);
    }

    // Blanket-implement the BL trait for anything that implements the AL trait.
    impl<T: al::RestCore + ?Sized> Rest for T {}

    #[enum_dispatch(Rest)]
    pub enum Item {
        Foo(il::Foo),
        Boo(il::Boo),
    }
}

fn main() {
    use bl::{Item, Rest};

    let a = Item::Foo(il::Foo);
    let b = Item::Boo(il::Boo);

    // Static dispatch through enum_dispatch, while implementations live elsewhere.
    println!("{}", a.get(1));
    println!("{}", b.get(1));

    println!("a.post => {}", a.post("hello"));
    println!("b.post => {}", b.post("hello"));

    println!("a.delete(2) => {}", a.delete(2));
    println!("b.delete(2) => {}", b.delete(2));
}
"
}
