    //
    // This is the main idea in radiate: you don't implement a trait for new ops;
    // you construct an `Op` from a name, an arity, and a closure.
    //
    // NOTE: we use `abs()` to avoid NaNs for negative inputs.
    let sqrt_plus_one = Op::vertex("sqrt_plus_one", 1, |xs: &[f64]| xs[0].abs().sqrt() + 1.0);

    // Your operator store: what operations are allowed at Vertex/Leaf nodes.
    // Add the custom op alongside the built-ins.
    let store = vec![
        (
            NodeType::Vertex,
            vec![Op::add(), Op::sub(), Op::mul(), Op::pow(), sqrt_plus_one],
        ),
        (NodeType::Leaf, vec![Op::var(0)]),
    ];

    // Just a tiny runtime check that the store was built.
    let vertex_ops = store
        .iter()
        .find(|(ty, _)| matches!(ty, NodeType::Vertex))
        .map(|(_, ops)| ops.len())
