name = "expectrl_pty_full_duplex"
version = "0.1.0"
edition = "2021"

[dependencies]
anyhow = "1"
expectrl = "0.7.1"
# Used only to set O_NONBLOCK on the PTY fd
nix = { version = "0.28", features = ["fcntl"] }
# Just to put *your* terminal into raw mode so you can type key-by-key
crossterm = "0.27"
",
  "main.rs": "use anyhow::Result;
use crossterm::terminal::{disable_raw_mode, enable_raw_mode};
use expectrl::spawn;
use nix::fcntl::{fcntl, FcntlArg, OFlag};
use std::io::{Read, Write};
use std::os::fd::AsRawFd;
use std::sync::mpsc;
use std::time::Duration;

fn set_nonblocking(fd: i32) -> Result<()> {
    let flags = OFlag::from_bits_truncate(fcntl(fd, FcntlArg::F_GETFL)?);
    fcntl(fd, FcntlArg::F_SETFL(flags | OFlag::O_NONBLOCK))?;
    Ok(())
}

fn main() -> Result<()> {
    // Make spawned interactive programs behave like a real terminal.
    std::env::set_var("TERM", "xterm-256color");

    eprintln!(
        "\
Full-duplex PTY demo (expectrl)\n\
- Your keyboard is forwarded to the child process *immediately* (raw mode).\n\
- Child output is printed as it arrives.\n\
- Type 'exit' + Enter (or Ctrl-D in the child) to quit.\n\
\n\
This demonstrates a safe concurrency pattern: one thread owns the Session\n\
(read + write), other threads communicate via a channel, and the PTY is\n\
non-blocking so reads never hold up writes.\n"
    );

    // Put *this* terminal into raw mode so we can read keystrokes (not lines).
    enable_raw_mode()?;

    // Ensure raw mode is always restored.
    struct RawModeGuard;
    impl Drop for RawModeGuard {
        fn drop(&mut self) {
            let _ = disable_raw_mode();
        }
    }
    let _guard = RawModeGuard;

    // Spawn something interactive. (On macOS, /bin/bash exists by default.)
    // You can replace this with e.g. "python3 -q".
    let mut session = spawn("/bin/bash --noprofile --norc")?;

    // Key bit: make PTY reads non-blocking so a read loop never blocks writes.
    let pty_fd = session.get_mut().as_raw_fd();
    set_nonblocking(pty_fd)?;

    // Channel for input bytes coming from stdin thread -> session owner loop.
    let (tx, rx) = mpsc::channel::<Vec<u8>>();

    // Thread: read *your* stdin (raw keystrokes) and forward bytes to channel.
    std::thread::spawn(move || {
        let mut stdin = std::io::stdin();
        let mut buf = [0u8; 1024];
        loop {
            match stdin.read(&mut buf) {
                Ok(0) => break,
                Ok(n) => {
                    // Forward exactly the bytes typed (including ESC sequences, Ctrl keys, etc.)
                    if tx.send(buf[..n].to_vec()).is_err() {
                        break;
                    }
                }
                Err(_) => break,
            }
        }
    });

    let mut stdout = std::io::stdout();
    let mut out_buf = [0u8; 8192];

    // Single-owner loop: handles BOTH read and write.
    // - Writes are driven by the channel.
    // - Reads are non-blocking (WouldBlock means "no output right now").
    loop {
        // 1) Apply any pending writes (drain quickly).
        // Use a short timeout so we don't busy-spin when idle.
        match rx.recv_timeout(Duration::from_millis(10)) {
            Ok(first) => {
                // Write the first chunk...
                if session.get_mut().write_all(&first).is_err() {
                    break;
                }
                let _ = session.get_mut().flush();

                // ...then drain the rest that arrived.
                while let Ok(more) = rx.try_recv() {
                    if session.get_mut().write_all(&more).is_err() {
                        break;
                    }
                    let _ = session.get_mut().flush();
                }
            }
            Err(mpsc::RecvTimeoutError::Timeout) => {
                // no input right now
            }
            Err(mpsc::RecvTimeoutError::Disconnected) => break,
        }

        // 2) Read any available output (non-blocking).
        loop {
            match session.read(&mut out_buf) {
                Ok(0) => {
                    // PTY closed / child exited.
                    writeln!(stdout, "\r\n[child exited]")?;
                    stdout.flush()?;
                    return Ok(());
                }
                Ok(n) => {
                    stdout.write_all(&out_buf[..n])?;
                    stdout.flush()?;
                }
                Err(e) if e.kind() == std::io::ErrorKind::WouldBlock => {
                    // Nothing more to read right now.
                    break;
                }
                Err(_) => {
                    writeln!(stdout, "\r\n[read error]")?;
                    stdout.flush()?;
                    return Ok(());
                }
            }
        }
    }

    // RawModeGuard restores terminal.
}
"
}
