    },
    middleware::{self, Next},
    response::{IntoResponse, Response},
    routing::get,
    Router,
};
use futures_util::{sink::SinkExt, stream::StreamExt};
use tower_http::cors::CorsLayer;

const ALLOWED_ORIGIN: &str = "https://www.example.com";

#[tokio::main]
async fn main() {
    tracing_subscriber::fmt()
        .with_env_filter(tracing_subscriber::EnvFilter::from_default_env())
        .init();

    // This is the important part: a route-level middleware that rejects
    // websocket handshakes unless the Origin is the allowed site.
    let ws_routes = Router::new()
        .route("/client/{session_id}", get(client_handler))
        .route_layer(middleware::from_fn(enforce_ws_origin));

    // Regular CORS is still fine for your normal HTTP endpoints.
    // Note: CORS does not "secure" websockets by itself; do the Origin check above.
    let cors = CorsLayer::new()
        .allow_origin(ALLOWED_ORIGIN.parse::<HeaderValue>().unwrap())
        .allow_methods([Method::GET, Method::POST]);

    let app = Router::new()
        .route("/", get(|| async { "ok" }))
        .merge(ws_routes)
        .layer(cors);

    let listener = tokio::net::TcpListener::bind("0.0.0.0:3000").await.unwrap();
    tracing::info!("listening on {}", listener.local_addr().unwrap());

    axum::serve(listener, app).await.unwrap();
}

async fn enforce_ws_origin<B>(req: Request<B>, next: Next<B>) -> Response {
    if is_websocket_handshake(&req) {
        let origin_ok = req
            .headers()
            .get(ORIGIN)
            .and_then(|v| v.to_str().ok())
            .is_some_and(|origin| origin == ALLOWED_ORIGIN);

        if !origin_ok {
            return StatusCode::FORBIDDEN.into_response();
        }
    }

    next.run(req).await
}

fn is_websocket_handshake<B>(req: &Request<B>) -> bool {
    let h = req.headers();

    let upgrade_ok = h
        .get(UPGRADE)
        .and_then(|v| v.to_str().ok())
        .is_some_and(|v| v.eq_ignore_ascii_case("websocket"));

    let connection_ok = h
        .get(CONNECTION)
        .and_then(|v| v.to_str().ok())
        .is_some_and(|v| v.to_ascii_lowercase().split(',').any(|p| p.trim() == "upgrade"));

    // Common indicator it's really a WS handshake.
    let has_ws_key = h.contains_key(SEC_WEBSOCKET_KEY);

    upgrade_ok && connection_ok && has_ws_key
}

async fn client_handler(
    ws: WebSocketUpgrade,
    Path(session_id): Path<String>,
) -> impl IntoResponse {
    ws.on_upgrade(move |socket| handle_socket(socket, session_id))
}

async fn handle_socket(mut socket: WebSocket, session_id: String) {
    tracing::info!(%session_id, "websocket connected");

    // Simple echo server
    while let Some(Ok(msg)) = socket.next().await {
        match msg {
            Message::Text(t) => {
                if socket.send(Message::Text(t)).await.is_err() {
                    break;
                }
            }
            Message::Binary(b) => {
                if socket.send(Message::Binary(b)).await.is_err() {
                    break;
                }
            }
            Message::Close(_) => break,
            _ => {}
        }
    }

    tracing::info!(%session_id, "websocket disconnected");
}
"
}
