type SysLogger = syslog::Logger<syslog::LoggerBackend, Formatter3164>;

#[derive(Clone, Copy, Debug)]
enum Level {
    Info,
    Warning,
    Error,
}

fn log_at(logger: &mut SysLogger, level: Level, msg: &str) {
    let result = match level {
        Level::Info => logger.info(msg),
        Level::Warning => logger.warning(msg),
        Level::Error => logger.err(msg),
    };

    // Centralized error handling (instead of repeating `.expect("Failed to log")` everywhere).
    result.expect("Failed to log");
}

/// Macro wrapper to:
/// - keep call-sites short
/// - capture file/line at the *call site* (functions can't do that)
/// - accept formatting like `println!`
macro_rules! slog {
    ($logger:expr, $level:expr, $($arg:tt)+) => {{
        let user_msg = format!($($arg)+);
        let full_msg = format!("[{}:{}] {}", file!(), line!(), user_msg);
        log_at($logger, $level, &full_msg);
    }};
}

