async fn main() {
    let (tx, mut rx) = mpsc::channel::<ParsedMessage>(16);

    // Producer: receives raw JSON as a String, parses exactly once into a borrowed struct,
    // and sends the self-contained object.
    let producer = tokio::spawn(async move {
        let inputs = [
            r#"{"data":"hello","more_data":"world"}"#.to_string(),
            r#"{"data":"tokio","more_data":"spawn"}"#.to_string(),
            r#"{"data":"borrowed","more_data":"serde"}"#.to_string(),
        ];

        for json in inputs {
            // No cloning: we move the String into ParsedMessage.
            let msg = parse_once(json);
            tx.send(msg).await.unwrap();
        }
    });

    // Consumer loop: each message is moved into its own tokio::spawn task.
    // This works because ParsedMessage owns the backing String, so the future can be 'static.
    while let Some(msg) = rx.recv().await {
        tokio::spawn(async move {
            msg.with_dependent(|_json, parsed| {
                // `parsed` is `&MyData<'_>` borrowing from the internal owned String.
                println!("parsed: data={:?}, more_data={:?}", parsed.data, parsed.more_data);
            });
