use opentelemetry_sdk::{resource::Resource, trace as sdktrace};
use tracing::{info, info_span, Instrument, Span};
use tracing_subscriber::{fmt::format::FmtSpan, layer::SubscriberExt, util::SubscriberInitExt, EnvFilter};

#[derive(Debug)]
struct RequestContext {
    /// This is the "request lifecycle" span.
    /// Store it and use it as the explicit parent when callbacks happen later/on other threads.
    request_span: Span,
}

impl RequestContext {
    fn new(request_id: u64) -> Self {
        let request_span = info_span!("request", request_id);
        Self { request_span }
    }
}

async fn stage1(ctx: Arc<RequestContext>) {
    // Key trick: set explicit parent, do NOT rely on Span::current().
    // This works even if the callback is invoked on a different thread with no span in scope.
    let span = info_span!(parent: &ctx.request_span, "stage1");

    async move {
        info!("stage1: begin");
        tokio::time::sleep(Duration::from_millis(80)).await;
        info!("stage1: end");
    }
    // Key trick: instrument the *future* so the span is re-entered on every poll,
    // even if the task moves between threads.
    .instrument(span)
    .await;
}

async fn upstream_call() {
    let span = info_span!(parent: &Span::current(), "upstream");
    async move {
        info!("upstream: connecting");
        tokio::time::sleep(Duration::from_millis(50)).await;
        info!("upstream: response received");
    }
    .instrument(span)
    .await;
}

async fn stage2(ctx: Arc<RequestContext>) {
    let stage2_span = info_span!(parent: &ctx.request_span, "stage2");

    async move {
        info!("stage2: begin");

        // This becomes a child of stage2 because stage2_span is current inside this future.
        upstream_call().await;

        tokio::time::sleep(Duration::from_millis(30)).await;
        info!("stage2: end");
    }
    .instrument(stage2_span)
    .await;
}

fn init_tracing() {
    // OpenTelemetry exporter -> stdout
    let exporter = opentelemetry_stdout::SpanExporter::default();

    let provider = sdktrace::TracerProvider::builder()
        .with_resource(Resource::new(vec![KeyValue::new(
            "service.name",
            "rehydrate-demo",
        )]))
        .with_simple_exporter(exporter)
        .build();

    let tracer = provider.tracer("rehydrate-demo");
    global::set_tracer_provider(provider);

    let otel_layer = tracing_opentelemetry::layer().with_tracer(tracer);

    tracing_subscriber::registry()
        .with(EnvFilter::from_default_env().add_directive("info".parse().unwrap()))
        .with(
            tracing_subscriber::fmt::layer()
                .with_thread_names(true)
                .with_thread_ids(true)
                // Show span open/close timing in stdout logs.
                .with_span_events(FmtSpan::NEW | FmtSpan::CLOSE),
        )
        .with(otel_layer)
        .init();
}

#[tokio::main(flavor = "multi_thread", worker_threads = 4)]
async fn main() {
    init_tracing();

    // Simulate a request being accepted.
    // We create the parent span once and keep it in a context object.
    let ctx = Arc::new(RequestContext::new(1));

    info!("callbacks will run later, potentially on different threads");

    // Simulate Pingora/Tokio calling hooks at arbitrary times.
    let h1 = tokio::spawn(stage1(ctx.clone()));
    let h2 = tokio::spawn({
        let ctx = ctx.clone();
        async move {
            tokio::time::sleep(Duration::from_millis(120)).await;
            stage2(ctx).await;
        }
