fn rewrite_imports_in_text(text: &str) -> String {
    let mut cur = text.to_string();

    // Two-phase fixed point:
    //  1) in-place path edits (safe, local)
    //  2) hoists (replace an entire subtree like `devices::{...}` -> `...`)
    // Repeat until no more edits.
    loop {
        let parse = SourceFile::parse(&cur);
        let file = parse.tree();

        let mut path_edits = Vec::<(TextRange, String)>::new();
        for use_item in file.syntax().descendants().filter_map(ast::Use::cast) {
            if let Some(tree) = use_item.use_tree() {
