        let file = parse.tree();

        let mut hoist_edits = Vec::<(TextRange, String)>::new();
        for use_item in file.syntax().descendants().filter_map(ast::Use::cast) {
            if let Some(tree) = use_item.use_tree() {
                collect_hoist_edits(&tree, &[], &mut hoist_edits);
            }
        }

        if hoist_edits.is_empty() {
