fn collect_path_edits(tree: &ast::UseTree, prefix: &[String], edits: &mut Vec<(TextRange, String)>) {
    let (mut local_segs, path_range) = match tree.path() {
        Some(p) => (path_segments(&p), Some(p.syntax().text_range())),
        None => (Vec::new(), None),
