  "main.rs": "use actix_web::{web, App, HttpResponse, HttpServer, Responder};
use log::{error, info, warn};
use std::time::Duration;
use tokio_util::sync::CancellationToken;

struct QueueHandler;

impl QueueHandler {
    async fn run(self, token: CancellationToken) {
        info!("queue: started");
        let mut interval = tokio::time::interval(Duration::from_secs(2));

        loop {
            tokio::select! {
                _ = token.cancelled() => {
                    info!("queue: shutdown requested");
                    break;
                }
                _ = interval.tick() => {
                    // Simulate one unit of work. If shutdown happens during this,
                    // we finish the current unit and then exit on the next loop.
                    info!("queue: received job, processing...");
                    tokio::time::sleep(Duration::from_secs(1)).await;
                    info!("queue: finished job");
                }
            }
        }

        // Optional cleanup/drain.
        info!("queue: cleaning up...");
        tokio::time::sleep(Duration::from_millis(300)).await;
        info!("queue: stopped");
    }
}

async fn index() -> impl Responder {
    HttpResponse::Ok().body("ok\n")
}

async fn slow() -> impl Responder {
    // Useful to test graceful shutdown: start a request, then press Ctrl+C.
    tokio::time::sleep(Duration::from_secs(5)).await;
    HttpResponse::Ok().body("slow response done\n")
}

enum ShutdownReason {
    CtrlC,
    ServerFinished(std::io::Result<()>),
    QueueFinished,
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    env_logger::init();

    let cancel = CancellationToken::new();

    // Build server future (do not spawn it).
    let server = HttpServer::new(|| {
        App::new()
            .route("/", web::get().to(index))
            .route("/slow", web::get().to(slow))
    })
    .bind(("127.0.0.1", 8080))?
    // How long Actix will wait for in-flight requests to finish after stop(true).
    .shutdown_timeout(30)
    .run();

    let server_handle = server.handle();
    tokio::pin!(server);

    // Build queue handler future (do not spawn it).
    let queue_fut = QueueHandler.run(cancel.clone());
    tokio::pin!(queue_fut);

    info!("http: listening on http://127.0.0.1:8080");
    info!("press Ctrl+C to stop");

    let mut server_finished = false;
    let mut queue_finished = false;

    let reason = tokio::select! {
        _ = tokio::signal::ctrl_c() => ShutdownReason::CtrlC,
        res = &mut server => ShutdownReason::ServerFinished(res),
        _ = &mut queue_fut => ShutdownReason::QueueFinished,
    };

    match reason {
        ShutdownReason::CtrlC => {
            info!("shutdown: Ctrl+C received");
            cancel.cancel();
            // stop(true) = graceful: wait for in-flight requests.
            server_handle.stop(true).await;
        }
        ShutdownReason::ServerFinished(res) => {
            server_finished = true;
            warn!("shutdown: server finished first: {res:?}");
            cancel.cancel();
        }
        ShutdownReason::QueueFinished => {
            queue_finished = true;
            warn!("shutdown: queue finished first");
            server_handle.stop(true).await;
        }
    }

    // Ensure both tasks are fully finished before exiting (no background work left).
    if !queue_finished {
        (&mut queue_fut).await;
        queue_finished = true;
    }

    if !server_finished {
        match (&mut server).await {
            Ok(()) => {}
            Err(e) => error!("http: server error while stopping: {e}"),
        }
        server_finished = true;
    }

    info!("shutdown: complete (server_finished={server_finished}, queue_finished={queue_finished})");
    Ok(())
}
"
}
