  "Cargo.toml": "[package]
name = "eventloop-stop-threads"
version = "0.1.0"
edition = "2021"

[dependencies]
termion = "2"
signal-hook = "0.3"
crossbeam-channel = "0.5"
",
  "main.rs": "use crossbeam_channel as chan;
use signal_hook::consts::{SIGINT, SIGTERM};
use signal_hook::iterator::Signals;
use std::io::{self, Read, Write};
use std::sync::{
    atomic::{AtomicBool, Ordering},
    Arc,
};
use std::thread;
use std::time::Duration;
use termion::raw::IntoRawMode;

#[derive(Debug)]
enum Message {
    Key(u8),
    Signal(i32),
    Quit(&'static str),
    WorkerDone(&'static str),
}

fn spawn_signal_thread(tx: chan::Sender<Message>) -> (thread::JoinHandle<()>, signal_hook::iterator::Handle) {
    let mut signals = Signals::new([SIGINT, SIGTERM]).expect("failed to register signals");
    let handle = signals.handle();

    let join = thread::spawn(move || {
        // This loop blocks waiting for signals.
        // It can be stopped from another thread by calling `handle.close()`.
        for sig in signals.forever() {
            let _ = tx.send(Message::Signal(sig));
            if sig == SIGINT || sig == SIGTERM {
                let _ = tx.send(Message::Quit("signal"));
            }
        }
        let _ = tx.send(Message::WorkerDone("signals"));
    });

    (join, handle)
}

fn spawn_key_thread(tx: chan::Sender<Message>, shutdown: Arc<AtomicBool>) -> thread::JoinHandle<()> {
    thread::spawn(move || {
        // `async_stdin` gives us a non-blocking reader.
        let mut stdin = termion::async_stdin();
        let ticker = chan::tick(Duration::from_millis(10));

        let mut buf = [0u8; 64];
        loop {
            if shutdown.load(Ordering::Relaxed) {
                break;
            }

            // Wait a bit (prevents busy-looping), but wake up frequently to check shutdown.
            let _ = ticker.recv();

            match stdin.read(&mut buf) {
                Ok(0) => {
                    // No input available right now.
                }
                Ok(n) => {
                    for &b in &buf[..n] {
                        let _ = tx.send(Message::Key(b));
                        if b == b'q' || b == b'Q' {
                            let _ = tx.send(Message::Quit("key"));
                        }
                    }
                }
                Err(_) => {
                    // If stdin breaks, just exit this worker.
                    break;
                }
            }
        }

        let _ = tx.send(Message::WorkerDone("keys"));
    })
}

fn main() {
    let (tx, rx) = chan::unbounded::<Message>();
    let shutdown = Arc::new(AtomicBool::new(false));

    // Put the terminal in raw mode so keypresses arrive immediately.
    let mut stdout = io::stdout().into_raw_mode().expect("raw mode");
    writeln!(
        stdout,
        "Press 'q' to quit, or send SIGINT/SIGTERM (Ctrl-C)."
    )
    .ok();
    stdout.flush().ok();

    // Spawn workers.
    let (sig_join, sig_handle) = spawn_signal_thread(tx.clone());
    let key_join = spawn_key_thread(tx.clone(), shutdown.clone());

    // Main event loop.
    while let Ok(msg) = rx.recv() {
        match msg {
            Message::Key(b) => {
                // Print visible ASCII keys.
                if (0x20..=0x7e).contains(&b) {
                    write!(stdout, "key: '{}'\r\n", b as char).ok();
                } else {
                    write!(stdout, "key byte: {b}\r\n").ok();
                }
                stdout.flush().ok();
            }
            Message::Signal(sig) => {
                writeln!(stdout, "signal: {sig}").ok();
                stdout.flush().ok();
            }
            Message::Quit(origin) => {
                writeln!(stdout, "quit requested by {origin}").ok();
                stdout.flush().ok();

                // Trigger shutdown for the key thread.
                shutdown.store(true, Ordering::Relaxed);

                // Stop the signal iterator immediately.
                sig_handle.close();

                break;
            }
            Message::WorkerDone(name) => {
                writeln!(stdout, "worker done: {name}").ok();
                stdout.flush().ok();
            }
        }
    }

    // Join threads.
    let _ = key_join.join();
    let _ = sig_join.join();

    writeln!(stdout, "bye").ok();
    stdout.flush().ok();
}
"
}
