type Type = LocalBoxedObservableClone<'static, bool, Infallible>;

fn nand(name: String, a: Type, b: Type) -> Type {
    a.combine_latest(b, |a, b| (a, b))
        .distinct()
        .tap(move |&(a, b)| print!("nand {name} ({a}, {b})"))
        .map(|(a, b)| !(a & b))
        .tap(|v| println!(" = {v}"))
        .box_it_clone()
