/// Wrap `next()` so re-entrant `next()` calls are queued and executed after the
/// current emission finishes (prevents `RefCell already borrowed` panics).
fn make_queued_next<S>(subj: Rc<RefCell<S>>) -> Rc<dyn Fn(bool)>
where
    S: Observer<Item = bool, Err = Infallible> + 'static,
{
    let emitting = Rc::new(Cell::new(false));
    let queue = Rc::new(RefCell::new(VecDeque::<bool>::new()));

    Rc::new(move |v: bool| {
        if emitting.get() {
            queue.borrow_mut().push_back(v);
            return;
        }

        emitting.set(true);
        {
            subj.borrow_mut().next(v);
        }

        loop {
            let next = queue.borrow_mut().pop_front();
            match next {
                Some(v) => subj.borrow_mut().next(v),
                None => break,
            }
        }

        emitting.set(false);
    })
}

fn flipflop(s: Type, r: Type) -> (Type, Type) {
    // Feedback state holders.
    // Put subjects behind Rc<RefCell<..>> so we can both (a) observe and (b) push next() into them.
    let s2 = Rc::new(RefCell::new(Local::behavior_subject::<bool, Infallible>(false)));
    let r2 = Rc::new(RefCell::new(Local::behavior_subject::<bool, Infallible>(false)));

    let s2_obs: Type = s2.borrow().clone().box_it_clone();
    let r2_obs: Type = r2.borrow().clone().box_it_clone();

    // Queueing next() breaks the re-entrant borrow that otherwise happens in the NAND cross-coupling.
    let s2_next = make_queued_next(s2);
    let r2_next = make_queued_next(r2);

    let q1 = nand("s".to_string(), s, s2_obs)
        .tap({
            let r2_next = r2_next.clone();
            move |v| (r2_next)(*v)
        })
        .box_it_clone();

    let q2 = nand("r".to_string(), r, r2_obs)
        .tap({
            let s2_next = s2_next.clone();
            move |v| (s2_next)(*v)
        })
        .box_it_clone();

    (q1, q2)
}

fn main() {
    let mut s = Local::behavior_subject::<bool, Infallible>(true);
    let mut r = Local::behavior_subject::<bool, Infallible>(true);

    let (q1, q2) = flipflop(s.clone().box_it_clone(), r.clone().box_it_clone());

