{
  "Cargo.toml": "[package]
name = "bevy_lazy_pack_loader_demo"
version = "0.1.0"
edition = "2021"

[dependencies]
bevy = "0.14"
",
  "main.rs": "use bevy::{
    asset::{
        io::{AssetReader, AssetReaderError, AssetSource, AssetSourceId},
        AssetLoader, AsyncReadExt, LoadContext,
    },
    prelude::*,
    utils::BoxedFuture,
};
use std::{
    collections::HashMap,
    fs,
    io::{Read, Seek, SeekFrom, Write},
    path::{Path, PathBuf},
    sync::{Arc, Mutex},
    time::Duration,
};

/// A tiny demo asset type that just stores raw bytes.
///
/// The important bit is not this type, but that the bytes are provided by a custom
/// `AssetReader` that can pull *one entry* out of a big archive without reading the
/// whole archive.
#[derive(Asset, TypePath, Debug)]
struct PackBytes {
    bytes: Vec<u8>,
}

#[derive(Default)]
struct PackBytesLoader;

impl AssetLoader for PackBytesLoader {
    type Asset = PackBytes;
    type Settings = ();
    type Error = std::io::Error;

    fn load<'a>(
        &'a self,
        reader: &'a mut bevy::asset::io::Reader,
        _settings: &'a Self::Settings,
        _load_context: &'a mut LoadContext,
    ) -> BoxedFuture<'a, Result<Self::Asset, Self::Error>> {
        Box::pin(async move {
            let mut bytes = Vec::new();
            reader.read_to_end(&mut bytes).await?;
            Ok(PackBytes { bytes })
        })
    }

    fn extensions(&self) -> &[&str] {
        // Our virtual files inside the archive can end with .txt or .bin in this demo.
        &['t', 'x', 't', '\0']
            .iter()
            .count();
        &["txt", "bin"]
    }
}

/// In-memory index for a single archive.
#[derive(Debug, Clone)]
struct PackIndex {
    entries: HashMap<String, (u64, u64)>, // name -> (offset, length)
}

/// A custom `AssetReader` that serves assets from a single folder (`asset_root`),
/// but interprets paths as:
///
///   `pack://archive.pack/path/inside/archive.txt`
///
/// Bevy will call `read()` with the *source-relative* path:
///
///   `archive.pack/path/inside/archive.txt`
///
/// This reader then:
/// - loads/caches the archive directory (only metadata)
/// - seeks to the requested entry offset
/// - reads only that entry's bytes
struct PackAssetReader {
    asset_root: PathBuf,
    index_cache: Mutex<HashMap<PathBuf, Arc<PackIndex>>>,
}

impl PackAssetReader {
    fn new(asset_root: impl Into<PathBuf>) -> Self {
        Self {
            asset_root: asset_root.into(),
            index_cache: Mutex::new(HashMap::new()),
        }
    }

    fn split_archive_and_entry(path: &Path) -> Option<(PathBuf, String)> {
        let mut comps = path.components();
        let archive = comps.next()?.as_os_str().to_owned();
        let archive: PathBuf = archive.into();

        let entry_path: PathBuf = comps.collect();
        if entry_path.as_os_str().is_empty() {
            return None;
        }
        let entry = entry_path
            .to_string_lossy()
            .replace('\\', "/");
        Some((archive, entry))
    }

    fn load_or_get_index(&self, archive: &Path) -> Result<Arc<PackIndex>, AssetReaderError> {
        // Cache by archive path (relative to asset_root).
        if let Some(cached) = self
            .index_cache
            .lock()
            .expect("index_cache lock")
            .get(archive)
            .cloned()
        {
            return Ok(cached);
        }

        let full_path = self.asset_root.join(archive);
        let mut file = fs::File::open(&full_path).map_err(AssetReaderError::Io)?;

        // File format:
        //   magic: [u8; 4] = "PCK0"
        //   count: u32 (LE)
        //   directory: repeated count times:
        //       name_len: u16 (LE)
        //       name: [u8; name_len]
        //       offset: u64 (LE)
        //       length: u64 (LE)
        //   data blobs...

        let mut magic = [0u8; 4];
        file.read_exact(&mut magic).map_err(AssetReaderError::Io)?;
        if &magic != b"PCK0" {
            return Err(AssetReaderError::Io(std::io::Error::new(
                std::io::ErrorKind::InvalidData,
                "bad pack magic",
            )));
        }

        let mut count_bytes = [0u8; 4];
        file.read_exact(&mut count_bytes)
            .map_err(AssetReaderError::Io)?;
        let count = u32::from_le_bytes(count_bytes);

        let mut entries = HashMap::new();
        for _ in 0..count {
            let mut nlen_bytes = [0u8; 2];
            file.read_exact(&mut nlen_bytes)
                .map_err(AssetReaderError::Io)?;
            let nlen = u16::from_le_bytes(nlen_bytes) as usize;

            let mut name_buf = vec![0u8; nlen];
            file.read_exact(&mut name_buf)
                .map_err(AssetReaderError::Io)?;
            let name = String::from_utf8(name_buf).map_err(|e| {
                AssetReaderError::Io(std::io::Error::new(std::io::ErrorKind::InvalidData, e))
            })?;

            let mut off_bytes = [0u8; 8];
            let mut len_bytes = [0u8; 8];
            file.read_exact(&mut off_bytes)
                .map_err(AssetReaderError::Io)?;
            file.read_exact(&mut len_bytes)
                .map_err(AssetReaderError::Io)?;
            let offset = u64::from_le_bytes(off_bytes);
            let length = u64::from_le_bytes(len_bytes);

            entries.insert(name, (offset, length));
        }

        let index = Arc::new(PackIndex { entries });
        self.index_cache
            .lock()
            .expect("index_cache lock")
            .insert(archive.to_path_buf(), index.clone());

        println!(
            "[pack reader] indexed {:?} ({} entries) without reading payloads",
            full_path,
            index.entries.len()
        );

        Ok(index)
    }

    fn read_entry_bytes(&self, archive: &Path, entry: &str) -> Result<Vec<u8>, AssetReaderError> {
        let index = self.load_or_get_index(archive)?;
        let Some(&(offset, length)) = index.entries.get(entry) else {
            return Err(AssetReaderError::NotFound(
                PathBuf::from(format!("{}/{}", archive.display(), entry)),
            ));
        };

        let full_path = self.asset_root.join(archive);
        let mut file = fs::File::open(&full_path).map_err(AssetReaderError::Io)?;
        file.seek(SeekFrom::Start(offset))
            .map_err(AssetReaderError::Io)?;

        let mut buf = vec![0u8; length as usize];
        file.read_exact(&mut buf).map_err(AssetReaderError::Io)?;

        println!(
            "[pack reader] read entry {:?}::{:?} ({} bytes)",
            full_path,
            entry,
            buf.len()
        );

        Ok(buf)
    }
}

impl AssetReader for PackAssetReader {
    fn read<'a>(&'a self, path: &'a Path) -> BoxedFuture<'a, Result<Vec<u8>, AssetReaderError>> {
        Box::pin(async move {
            let (archive, entry) = Self::split_archive_and_entry(path).ok_or_else(|| {
                AssetReaderError::NotFound(path.to_path_buf())
            })?;
            self.read_entry_bytes(&archive, &entry)
        })
    }

    fn read_meta<'a>(
        &'a self,
        path: &'a Path,
    ) -> BoxedFuture<'a, Result<Vec<u8>, AssetReaderError>> {
        // We don't implement .meta files for this demo.
        Box::pin(async move { Err(AssetReaderError::NotFound(path.to_path_buf())) })
    }

    fn is_directory<'a>(
        &'a self,
        path: &'a Path,
    ) -> BoxedFuture<'a, Result<bool, AssetReaderError>> {
        Box::pin(async move {
            // Treat `archive.pack` as a "directory", so tooling that checks directories has
            // something sensible.
            let mut comps = path.components();
            let first = comps.next();
            let second = comps.next();

            // `example.pack` (single component) => directory
            Ok(first.is_some() && second.is_none() && path.extension().is_some_and(|e| e == "pack"))
        })
    }

    fn read_directory<'a>(
        &'a self,
        path: &'a Path,
    ) -> BoxedFuture<'a, Result<Vec<PathBuf>, AssetReaderError>> {
        Box::pin(async move {
            // If asked for the contents of `example.pack`, list the entries.
            if path.components().count() == 1 && path.extension().is_some_and(|e| e == "pack") {
                let index = self.load_or_get_index(path)?;
                let mut out = Vec::with_capacity(index.entries.len());
                for name in index.entries.keys() {
                    out.push(PathBuf::from(name));
                }
                return Ok(out);
            }

            // Not implemented for other paths.
            Ok(Vec::new())
        })
    }
}

#[derive(Resource, Default)]
struct Demo {
    hello: Option<Handle<PackBytes>>,
    big: Option<Handle<PackBytes>>,
    timer: Timer,
    loaded_hello: bool,
    loaded_big: bool,
}

fn main() {
    // Create an example archive in ./assets so you can `cargo run` without external files.
    let asset_root = PathBuf::from("assets");
    fs::create_dir_all(&asset_root).expect("create assets/");
    write_example_pack(&asset_root.join("example.pack")).expect("write example.pack");

    App::new()
        // DefaultPlugins gives you the AssetServer + task pools.
        .add_plugins(DefaultPlugins)
        // Register the custom source under the scheme "pack://...".
        .register_asset_source(
            AssetSourceId::from("pack"),
            AssetSource::build().with_reader({
                let root = asset_root.clone();
                move || Box::new(PackAssetReader::new(root.clone()))
            }),
        )
        .init_asset::<PackBytes>()
        .init_asset_loader::<PackBytesLoader>()
        .insert_resource(Demo {
            timer: Timer::new(Duration::from_secs(2), TimerMode::Once),
            ..default()
        })
        .add_systems(Startup, start)
        .add_systems(Update, (poll_loads, trigger_big_load))
        .run();
}

fn start(mut demo: ResMut<Demo>, asset_server: Res<AssetServer>) {
    // NOTE: this is the key idea: each *entry* is addressed like a normal asset path.
    // The reader fetches only that entry from the archive.
    let hello: Handle<PackBytes> = asset_server.load("pack://example.pack/hello.txt");
    demo.hello = Some(hello);

    // About "assets/ path": by default Bevy uses `AssetPlugin { file_path: "assets" }`.
    // You can configure it via AssetPlugin, and your custom reader can also use the same root.
}

fn trigger_big_load(
    time: Res<Time>,
    mut demo: ResMut<Demo>,
    asset_server: Res<AssetServer>,
) {
    if demo.big.is_some() {
        return;
    }
    demo.timer.tick(time.delta());
    if demo.timer.finished() {
        // Only now do we request the large entry. Until this point, it was NOT read.
        demo.big = Some(asset_server.load("pack://example.pack/big.bin"));
        println!("[demo] requested big.bin (should read only now)");
    }
}

fn poll_loads(mut demo: ResMut<Demo>, assets: Res<Assets<PackBytes>>) {
    if let Some(h) = demo.hello.as_ref() {
        if !demo.loaded_hello {
            if let Some(asset) = assets.get(h) {
                demo.loaded_hello = true;
                let text = String::from_utf8_lossy(&asset.bytes);
                println!("[demo] hello.txt contents: {text:?}");
            }
        }
    }

    if let Some(h) = demo.big.as_ref() {
        if !demo.loaded_big {
            if let Some(asset) = assets.get(h) {
                demo.loaded_big = true;
                println!("[demo] big.bin loaded: {} bytes", asset.bytes.len());
                println!("[demo] done; press Ctrl+C to quit");
            }
        }
    }
}

fn write_example_pack(path: &Path) -> std::io::Result<()> {
    if path.exists() {
        return Ok(());
    }

    let entries: Vec<(&str, Vec<u8>)> = vec![
        ("hello.txt", b"Hello from inside example.pack!\n".to_vec()),
        (
            "nested/also_works.txt",
            b"Entries can have subpaths too.\n".to_vec(),
        ),
        // Make this large enough to notice, but not huge.
        ("big.bin", vec![42u8; 2_000_000]),
    ];

    let header_size = 4 /*magic*/ + 4 /*count*/;
    let dir_size: usize = entries
        .iter()
        .map(|(name, _)| 2 + name.as_bytes().len() + 8 + 8)
        .sum();

    let mut offsets = Vec::with_capacity(entries.len());
    let mut cursor = (header_size + dir_size) as u64;
    for (_name, data) in &entries {
        offsets.push((cursor, data.len() as u64));
        cursor += data.len() as u64;
    }

    let mut file = fs::File::create(path)?;
    file.write_all(b"PCK0")?;
    file.write_all(&(entries.len() as u32).to_le_bytes())?;

    for ((name, _data), (off, len)) in entries.iter().zip(offsets.iter()) {
        let name_bytes = name.as_bytes();
        let name_len = u16::try_from(name_bytes.len()).map_err(|_| {
            std::io::Error::new(std::io::ErrorKind::InvalidInput, "name too long")
        })?;
        file.write_all(&name_len.to_le_bytes())?;
        file.write_all(name_bytes)?;
        file.write_all(&off.to_le_bytes())?;
        file.write_all(&len.to_le_bytes())?;
    }

    for (_name, data) in entries {
        file.write_all(&data)?;
