#[derive(Debug, Clone)]
pub struct Event(pub u64);

#[derive(Debug)]
pub struct RecvError;

/// A handle you can use to initiate a graceful shutdown.
#[derive(Clone, Debug)]
pub struct Shutdown {
    token: CancellationToken,
}

impl Shutdown {
    pub fn trigger(&self) {
        self.token.cancel();
    }

    pub fn token(&self) -> CancellationToken {
        self.token.clone()
    }
}

pub fn events_channel() -> (EventSender, EventStreamFactory, Shutdown) {
    let (tx, _rx) = broadcast::channel(20);
    let token = CancellationToken::new();

    let shutdown = Shutdown { token: token.clone() };

    (
        EventSender {
            tx: tx.clone(),
            shutdown: token.clone(),
        },
        EventStreamFactory { tx, shutdown: token },
        shutdown,
