        self.shutdown.clone()
    }
}

#[derive(Clone, Debug)]
pub struct EventStreamFactory {
    tx: Sender<Event>,
    shutdown: CancellationToken,
}

impl EventStreamFactory {
    pub fn all_events(&self) -> impl Stream<Item = Result<Event, RecvError>> + Send + 'static {
        // Clone everything needed so the returned stream is 'static.
        let rx = self.tx.subscribe();
        let shutdown = self.shutdown.clone();

        BroadcastStream::new(rx)
            // This is the important bit: end the stream on shutdown, even if
            // there are still Sender clones alive somewhere.
            .take_until(shutdown.cancelled())
