                    Ok(ev) => Some(Ok(ev)),
                    // In a real app you might map this to an error or emit a special event.
                    Err(BroadcastStreamRecvError::Lagged(_)) => None,
                    // If all senders are dropped, the channel closes; you can end as well.
                    Err(BroadcastStreamRecvError::Closed) => Some(Err(RecvError)),
                }
            })
    }
}

