    let (sender, factory, shutdown) = events_channel();

    // Producer #1 (holds a cloned sender)
    let producer_sender = sender.clone();
    let producer_shutdown = shutdown.token();
    tokio::spawn(async move {
        let mut i = 0u64;
        loop {
            tokio::select! {
                _ = producer_shutdown.cancelled() => {
                    eprintln!("producer: shutdown requested");
                    break;
                }
                _ = tokio::time::sleep(Duration::from_millis(200)) => {
                    producer_sender.send(Event(i));
                    i += 1;
                }
            }
        }
    });

    // Consumer (this models your SSE stream)
    let mut stream = factory.all_events();
    let consumer = tokio::spawn(async move {
        while let Some(item) = stream.next().await {
            match item {
                Ok(ev) => println!("SSE event: {ev:?}"),
                Err(_) => {
                    eprintln!("consumer: channel closed");
                    break;
                }
            }
        }
        eprintln!("consumer: stream ended");
    });

    // Trigger shutdown on Ctrl-C (or after 3 seconds, so `cargo run` shows behavior without input).
    tokio::select! {
        _ = tokio::signal::ctrl_c() => {
            eprintln!("main: Ctrl-C received");
        }
        _ = tokio::time::sleep(Duration::from_secs(3)) => {
            eprintln!("main: timeout reached, shutting down");
        }
    }

    shutdown.trigger();

    let _ = consumer.await;
    eprintln!("main: done");
}
