  "main.rs": "use anyhow::{anyhow, Result};
use serde::{Deserialize, Serialize};
use serde_json::json;
use std::collections::HashMap;

// -----------------------------
// Minimal Notion-like structures
// -----------------------------

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TextObject {
    pub content: String,
    pub link: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RichTextObject {
    pub text: TextObject,
    pub href: Option<String>,
    pub plain_text: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SelectObject {
    pub id: Option<String>,
    pub color: Option<String>,
    pub name: String,
}

/// What the Notion API wants for page properties:
/// HashMap<property_name, property_value>
///
/// Serialized shape matches Notion's pattern:
/// {"Name": {"title": [...]}, "Icon url": {"url": "..."}, "Roles": {"multi_select": [...]}}
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(untagged)]
pub enum PropertyValue {
    Title { title: Vec<RichTextObject> },
    Url { url: String },
    MultiSelect { multi_select: Vec<SelectObject> },
}

// -----------------------------
// "Field attributes" driven approach
//
// Instead of a custom proc-macro attribute like #[notion_property(...)],
// this example uses standard serde field attributes:
//   - #[serde(rename = "...")]  -> Notion property name
//   - wrapper types             -> Notion property type
//
// This keeps it self-contained (no proc-macro crate needed) and lets you
// convert ANY such struct into HashMap<String, PropertyValue>.
// -----------------------------

/// Internal tagged representation used only during struct serialization.
///
/// Each field wrapper serializes to this, so we can later turn it into a Notion `PropertyValue`.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(tag = "notion_type", content = "value", rename_all = "snake_case")]
enum NotionField {
    Title(String),
    Url(String),
    MultiSelect(Vec<serde_json::Value>),
}

#[derive(Debug, Clone, Deserialize)]
pub struct NotionTitle(pub String);

impl Serialize for NotionTitle {
    fn serialize<S>(&self, serializer: S) -> std::result::Result<S::Ok, S::Error>
    where
        S: serde::Serializer,
    {
        NotionField::Title(self.0.clone()).serialize(serializer)
    }
}

#[derive(Debug, Clone, Deserialize)]
pub struct NotionUrl(pub String);

impl Serialize for NotionUrl {
    fn serialize<S>(&self, serializer: S) -> std::result::Result<S::Ok, S::Error>
    where
        S: serde::Serializer,
    {
        NotionField::Url(self.0.clone()).serialize(serializer)
    }
}

#[derive(Debug, Clone, Deserialize)]
pub struct NotionMultiSelect(pub Vec<serde_json::Value>);

impl Serialize for NotionMultiSelect {
    fn serialize<S>(&self, serializer: S) -> std::result::Result<S::Ok, S::Error>
    where
        S: serde::Serializer,
    {
        NotionField::MultiSelect(self.0.clone()).serialize(serializer)
    }
}

fn json_value_to_select_name(v: &serde_json::Value) -> String {
    if let Some(s) = v.as_str() {
        s.to_string()
    } else {
        // Fallback for numbers/objects/etc.
        v.to_string()
    }
}

fn notion_field_to_property_value(field: NotionField) -> PropertyValue {
    match field {
        NotionField::Title(content) => PropertyValue::Title {
            title: vec![RichTextObject {
                text: TextObject {
                    content,
                    link: None,
                },
                href: None,
                plain_text: None,
            }],
        },
        NotionField::Url(url) => PropertyValue::Url { url },
        NotionField::MultiSelect(values) => PropertyValue::MultiSelect {
            multi_select: values
                .into_iter()
                .map(|v| SelectObject {
                    id: None,
                    color: None,
                    name: json_value_to_select_name(&v),
                })
                .collect(),
        },
    }
}

/// Generic conversion for any serde-serializable struct whose field *values*
/// serialize into `NotionField` (done here via wrapper types like `NotionTitle`).
fn to_notion_properties<T: Serialize>(value: &T) -> Result<HashMap<String, PropertyValue>> {
    let v = serde_json::to_value(value)?;
    let obj = v
        .as_object()
        .ok_or_else(|| anyhow!("expected struct to serialize into a JSON object"))?;

    let mut out = HashMap::<String, PropertyValue>::new();

    for (prop_name, prop_value) in obj {
        // If you use skip_serializing_if on Option fields, None won't appear at all.
        // But handle explicit null defensively.
        if prop_value.is_null() {
            continue;
        }

        let field: NotionField = serde_json::from_value(prop_value.clone())?;
        out.insert(prop_name.clone(), notion_field_to_property_value(field));
    }

    Ok(out)
}

// -----------------------------
// Your domain struct
// -----------------------------

