fn draw_indicators(mut gizmos: Gizmos, q: Query<&Transform, With<RotatingCube>>) {
    let xf = q.single();

    // We'll pretend our "raycast" hit the cube's LOCAL +Z face.
    // So the face normal in world space is the cube's rotation applied to +Z.
    let normal = (xf.rotation * Vec3::Z).normalize();

    // Face center for a unit cube is half a unit along its face normal.
    let face_center = xf.translation + normal * 0.5;

    // Draw cube's axes for reference.
    let origin = xf.translation;
    gizmos.line(origin, origin + xf.rotation * Vec3::X, Color::srgb(1.0, 0.0, 0.0));
    gizmos.line(origin, origin + xf.rotation * Vec3::Y, Color::srgb(0.0, 1.0, 0.0));
    gizmos.line(origin, origin + xf.rotation * Vec3::Z, Color::srgb(0.0, 0.5, 1.0));

    // --- 1) Naive alignment: align +Z to the normal.
    // This is missing the "twist" around the normal, so it won't stay flush-aligned
    // with the cube's face orientation as the cube spins.
    let naive_rot = Quat::from_rotation_arc(Vec3::Z, normal);

    gizmos.rect(
        bevy::math::Isometry3d::new(face_center + normal * 0.01, naive_rot),
        Vec2::new(1.0, 1.0),
        Color::WHITE,
    );

    // --- 2) Correct alignment: build a full orthonormal basis (tangent/bitangent/normal)
    // where the normal matches the hit normal AND the tangent direction is derived from the
    // cube's own rotated axes (so the "twist" matches the cube).
    //
    // Pick a reference direction from the cube's orientation (local +X in world space),
    // then project it onto the plane perpendicular to the face normal.
    let ref_dir = xf.rotation * Vec3::X;
    let mut tangent = ref_dir - normal * ref_dir.dot(normal);

    // If ref_dir happens to be almost parallel to normal, fall back to another axis.
    if tangent.length_squared() < 1e-6 {
        let ref_dir2 = xf.rotation * Vec3::Y;
        tangent = ref_dir2 - normal * ref_dir2.dot(normal);
    }
    let tangent = tangent.normalize();

    // Right-handed basis: X=tangent, Y=bitangent, Z=normal
    let bitangent = normal.cross(tangent).normalize();

    let rot_mat = Mat3::from_cols(tangent, bitangent, normal);
    let correct_rot = Quat::from_mat3(&rot_mat);

    gizmos.rect(
        bevy::math::Isometry3d::new(face_center + normal * 0.02, correct_rot),
        Vec2::new(1.0, 1.0),
        Color::srgb(1.0, 0.85, 0.1),
    );

    // Extra: draw the basis vectors at the face center
    gizmos.line(
        face_center,
        face_center + tangent * 0.35,
        Color::srgb(1.0, 0.0, 1.0),
    );
    gizmos.line(
        face_center,
        face_center + bitangent * 0.35,
        Color::srgb(0.0, 1.0, 1.0),
    );
    gizmos.line(
        face_center,
        face_center + normal * 0.35,
        Color::srgb(1.0, 1.0, 0.0),
    );
}
"
