  "main.rs": "use anyhow::{anyhow, Context, Result};
use cms::content_info::ContentInfo;
use cms::signed_data::SignedData;
use der::asn1::{Any, ObjectIdentifier, OctetString};
use der::{Decode, Sequence};

/// A more permissive CMS ContentInfo (same shape as RFC5652),
/// useful when the strict `cms` structs fail to decode.
#[derive(Debug, Clone, Sequence)]
struct ContentInfoCompat {
    content_type: ObjectIdentifier,

    // ContentInfo ::= SEQUENCE {
    //   contentType ContentType,
    //   content [0] EXPLICIT ANY DEFINED BY contentType }
    #[asn1(context_specific = "0", tag_mode = "EXPLICIT", optional = "true")]
    content: Option<Any>,
}

/// A permissive SignedData decoder which only fully parses the parts we need
/// (version + encapContentInfo). Everything else is left as `Any`.
#[derive(Debug, Clone, Sequence)]
struct SignedDataCompat {
    version: u8,

    // digestAlgorithms SET OF AlgorithmIdentifier
    // We don't need them for SCEP message extraction, so keep as raw ASN.1.
    digest_algorithms: Any,

    encap_content_info: EncapsulatedContentInfoCompat,

    // certificates [0] IMPLICIT CertificateSet OPTIONAL
    #[asn1(context_specific = "0", tag_mode = "IMPLICIT", optional = "true")]
    certificates: Option<Any>,

    // crls [1] IMPLICIT RevocationInfoChoices OPTIONAL
    #[asn1(context_specific = "1", tag_mode = "IMPLICIT", optional = "true")]
    crls: Option<Any>,

    // signerInfos SET OF SignerInfo
    signer_infos: Any,
}

#[derive(Debug, Clone, Sequence)]
struct EncapsulatedContentInfoCompat {
    e_content_type: ObjectIdentifier,

    // eContent [0] EXPLICIT OCTET STRING OPTIONAL
    #[asn1(context_specific = "0", tag_mode = "EXPLICIT", optional = "true")]
    e_content: Option<OctetString>,
}

fn main() -> Result<()> {
    let path = std::env::args()
        .nth(1)
        .ok_or_else(|| anyhow!("usage: cargo run -- <cms-der-file>"))?;

    let body = std::fs::read(&path).with_context(|| format!("reading {path}"))?;
    println!("read {} bytes from {}", body.len(), path);

    // 1) Decode outer ContentInfo using the `cms` crate.
    let ci = ContentInfo::from_der(&body).context("decoding outer ContentInfo (cms crate)")?;
    println!("outer contentType: {}", ci.content_type);

    // 2) Try strict SignedData decode (this is what you attempted).
    if let Some(any) = ci.content.as_ref() {
        match any.decode_as::<SignedData>() {
            Ok(sd) => {
                println!("cms::SignedData decoded OK");
                println!("  version: {}", sd.version);
                println!("  encapContentInfo.eContentType: {}", sd.encap_content_info.e_content_type);

                if let Some(octets) = sd.encap_content_info.e_content.as_ref() {
                    println!("  encapContentInfo.eContent octets: {} bytes", octets.as_bytes().len());
                    decode_inner_contentinfo(octets.as_bytes())?;
                } else {
                    println!("  encapContentInfo.eContent: <absent>");
                }

                return Ok(());
            }
            Err(e) => {
                println!("cms::SignedData decode failed: {e:?}");
                println!("falling back to a permissive ASN.1 decoder to extract eContent...");
            }
        }
    } else {
        println!("outer ContentInfo has no [0] content");
        return Ok(());
    }

    // 3) Fallback: decode with permissive structs and still extract SCEP payload.
    let ci2 = ContentInfoCompat::from_der(&body).context("decoding outer ContentInfo (compat)")?;
    println!("outer(compat) contentType: {}", ci2.content_type);

    let any2 = ci2
        .content
        .as_ref()
        .ok_or_else(|| anyhow!("outer(compat) ContentInfo missing content"))?;

    let sd2: SignedDataCompat = any2
        .decode_as()
        .context("decoding SignedData (compat)")?;

    println!("signedData(compat) version: {}", sd2.version);
    println!("signedData(compat) encapContentInfo.eContentType: {}", sd2.encap_content_info.e_content_type);

    let econtent = sd2
        .encap_content_info
        .e_content
        .as_ref()
        .ok_or_else(|| anyhow!("SignedData encapContentInfo.eContent is absent"))?;

    let ebytes = econtent.as_bytes();
    println!("signedData(compat) encapContentInfo.eContent: {} bytes", ebytes.len());
    println!("eContent first 32 bytes: {}", hex::encode(&ebytes[..ebytes.len().min(32)]));

    decode_inner_contentinfo(ebytes)?;

    Ok(())
}

fn decode_inner_contentinfo(der_bytes: &[u8]) -> Result<()> {
    // In SCEP PKIOperation, the SignedData's eContent is typically another CMS ContentInfo,
    // usually EnvelopedData (1.2.840.113549.1.7.3).

    match ContentInfo::from_der(der_bytes) {
        Ok(inner) => {
            println!("inner ContentInfo (cms) contentType: {}", inner.content_type);
            println!("inner ContentInfo (cms) content present: {}", inner.content.is_some());
        }
        Err(e) => {
            println!("inner ContentInfo (cms) decode failed: {e:?}");
        }
    }

    let inner2 = ContentInfoCompat::from_der(der_bytes).context("decoding inner ContentInfo (compat)")?;
    println!("inner ContentInfo (compat) contentType: {}", inner2.content_type);
    println!("inner ContentInfo (compat) content present: {}", inner2.content.is_some());

    Ok(())
}
"
