pub trait BaseParser<'tok> {
    type InputToken: PartialEq + fmt::Display + 'tok;

    // `'src` is the lifetime of the input *container* (e.g. a slice borrow).
    // The token type itself can still borrow from `'tok`.
    type Input<'src>: ChumskyInput<'src, Token = Self::InputToken, Span = SimpleSpan<usize>>
    where
