where
    for<'src> Self: BaseParser<'tok, Input<'src> = &'src [Self::InputToken]>,
{
    fn parse_this_owned(input: Vec<Self::InputToken>) -> Result<Self::Output, Vec<String>> {
        <Self as BaseParser<'tok>>::parse_this(input.as_slice())
    }
