/// Delete any whitespace immediately before the cursor, then insert a character.
///
/// Key detail: we *invoke* a deletion command, then return a normal insertion
/// command (which positions the cursor after the inserted character).
struct TrimWsThenInsert {
    ch: char,
}

impl TrimWsThenInsert {
    fn new(ch: char) -> Self {
        Self { ch }
    }
}

impl ConditionalEventHandler for TrimWsThenInsert {
    fn handle(
        &self,
        _event: &Event,
        count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();

        // Count whitespace immediately before the cursor.
        let ws_count = line[..pos]
            .chars()
            .rev()
            .take_while(|c| c.is_whitespace())
            .count();

        if ws_count > 0 {
            // Execute deletion now...
            context.invoke(Cmd::BackwardDeleteChar(ws_count as RepeatCount));
        }

        // ...then do a normal self-insert so the cursor ends up after the inserted char.
        Some(Cmd::SelfInsert(count, self.ch))
    }
}

